output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?actorLabel WHERE {
  wd:Q401278 rdfs:label ?actorLabel .
  FILTER(LANG(?actorLabel) = 'en')
}

args.sparql:
SELECT ?actorLabel WHERE {
  ?character wdt:P31 wd:Q4823191;
             wdt:P179 wd:Q2168243;
             rdfs:label ?characterLabel.
  FILTER (LANG(?characterLabel) = 'en' && CONTAINS(LCASE(?characterLabel), 'stan smith')).
  ?character wdt:P1532 ?actor.
  ?actor rdfs:label ?actorLabel.
  FILTER (LANG(?actorLabel) = 'en').
}
